import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import {
  Plus, Search, Users, Bell, FileText,
  ClipboardCheck, Heart, Shield, Clock
} from "lucide-react";

const SecretaryPortal = () => {
  const [students, setStudents] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [studentDialogOpen, setStudentDialogOpen] = useState(false);
  const [announcementDialogOpen, setAnnouncementDialogOpen] = useState(false);
  const user = authService.getUser();

  const kenyaClasses = [
    "PP1", "PP2",
    "Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5", "Grade 6",
    "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"
  ];

  const [studentForm, setStudentForm] = useState({
    admission_number: "",
    full_name: "",
    date_of_birth: "",
    gender: "male",
    class_name: "",
    stream: "",
    guardian_name: "",
    guardian_phone: "",
    guardian_email: "",
    guardian_relationship: "parent",
    secondary_guardian_name: "",
    secondary_guardian_phone: "",
    secondary_guardian_email: "",
    secondary_guardian_relationship: "",
    blood_type: "",
    allergies: "",
    chronic_conditions: "",
    disabilities: "",
    immunization_status: "",
    medical_info: ""
  });

  const [announcementForm, setAnnouncementForm] = useState({
    title: "",
    content: "",
    target_audience: "all",
    priority: "normal"
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [studentsRes, announcementsRes] = await Promise.all([
        apiClient.get("/students?approval_status=all"),
        apiClient.get("/announcements?approval_status=all"),
      ]);
      setStudents(studentsRes.data);
      setAnnouncements(announcementsRes.data);
    } catch (error) {
      toast.error("Failed to fetch data");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmitStudent = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/students", studentForm);
      toast.success(
        res.data.approval_status === "pending"
          ? "Student submitted for approval"
          : "Student added successfully"
      );
      setStudentDialogOpen(false);
      resetStudentForm();
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.detail || "Failed to add student");
    }
  };

  const handleSubmitAnnouncement = async (e) => {
    e.preventDefault();
    try {
      const res = await apiClient.post("/announcements", announcementForm);
      toast.success(
        res.data.approval_status === "pending"
          ? "Announcement submitted for approval"
          : "Announcement posted"
      );
      setAnnouncementDialogOpen(false);
      setAnnouncementForm({
        title: "",
        content: "",
        target_audience: "all",
        priority: "normal"
      });
      fetchData();
    } catch (error) {
      toast.error(error.response?.data?.detail || "Failed to post announcement");
    }
  };

  const resetStudentForm = () => {
    setStudentForm({
      admission_number: "",
      full_name: "",
      date_of_birth: "",
      gender: "male",
      class_name: "",
      stream: "",
      guardian_name: "",
      guardian_phone: "",
      guardian_email: "",
      guardian_relationship: "parent",
      secondary_guardian_name: "",
      secondary_guardian_phone: "",
      secondary_guardian_email: "",
      secondary_guardian_relationship: "",
      blood_type: "",
      allergies: "",
      chronic_conditions: "",
      disabilities: "",
      immunization_status: "",
      medical_info: ""
    });
  };

  const filteredStudents = students.filter((s) =>
    s.full_name?.toLowerCase().includes(search.toLowerCase()) ||
    s.admission_number?.toLowerCase().includes(search.toLowerCase())
  );

  const approvalColor = (status) => {
    if (status === "approved") return "bg-green-500/15 text-green-400";
    if (status === "rejected") return "bg-red-500/15 text-red-400";
    return "bg-yellow-500/15 text-yellow-400";
  };

  const pendingStudents = students.filter(s => s.approval_status === "pending").length;
  const approvedStudents = students.filter(s => s.approval_status === "approved").length;

  if (loading) {
    return <div className="text-center py-12 text-slate-400">Loading...</div>;
  }

  return (
    <div className="space-y-6" data-testid="secretary-portal">

      {/* HEADER */}
      <div className="bg-gradient-to-r from-amber-600/20 to-orange-600/20 border border-amber-500/20 rounded-2xl p-8">
        <h2 className="text-4xl font-bold text-white">Secretary Portal</h2>
        <p className="text-amber-300/70 mt-2 text-lg">
          Welcome, {user?.full_name}
        </p>
        <p className="text-amber-400/50 text-sm mt-1">
          Manage student records & announcements
        </p>
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader>
            <CardTitle className="text-slate-400 text-sm flex justify-between">
              Total Students <Users className="w-5 h-5 text-amber-400" />
            </CardTitle>
          </CardHeader>
          <CardContent className="text-white text-3xl font-bold">
            {students.length}
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader>
            <CardTitle className="text-slate-400 text-sm flex justify-between">
              Approved <ClipboardCheck className="w-5 h-5 text-green-400" />
            </CardTitle>
          </CardHeader>
          <CardContent className="text-green-400 text-3xl font-bold">
            {approvedStudents}
          </CardContent>
        </Card>

        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardHeader>
            <CardTitle className="text-slate-400 text-sm flex justify-between">
              Pending <Clock className="w-5 h-5 text-yellow-400" />
            </CardTitle>
          </CardHeader>
          <CardContent className="text-yellow-400 text-3xl font-bold">
            {pendingStudents}
          </CardContent>
        </Card>
      </div>

      {/* TABS */}
      <Tabs defaultValue="students" className="space-y-6">

        <TabsList className="bg-[#0F1A2A] border border-[#1E293B]">
          <TabsTrigger value="students">Students</TabsTrigger>
          <TabsTrigger value="announcements">Announcements</TabsTrigger>
        </TabsList>

        {/* STUDENTS */}
        <TabsContent value="students">
          <Card className="bg-[#1A2332] border-[#1E293B]">
            <CardHeader>
              <div className="flex justify-between items-center gap-3">
                <CardTitle className="text-white">Student Records</CardTitle>

                <div className="flex gap-3">
                  <Input
                    placeholder="Search..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-64"
                  />

                  <Dialog open={studentDialogOpen} onOpenChange={setStudentDialogOpen}>
                    <DialogTrigger asChild>
                      <Button className="bg-amber-600 hover:bg-amber-700">
                        <Plus className="w-4 h-4 mr-2" /> Add Student
                      </Button>
                    </DialogTrigger>

                    <DialogContent className="max-w-4xl">
                      <DialogHeader>
                        <DialogTitle>Register Student</DialogTitle>
                      </DialogHeader>

                      <form onSubmit={handleSubmitStudent} className="space-y-4">

                        <Input placeholder="Admission Number"
                          value={studentForm.admission_number}
                          onChange={(e) =>
                            setStudentForm({ ...studentForm, admission_number: e.target.value })
                          }
                          required
                        />

                        <Input placeholder="Full Name"
                          value={studentForm.full_name}
                          onChange={(e) =>
                            setStudentForm({ ...studentForm, full_name: e.target.value })
                          }
                          required
                        />

                        <Input type="date"
                          value={studentForm.date_of_birth}
                          onChange={(e) =>
                            setStudentForm({ ...studentForm, date_of_birth: e.target.value })
                          }
                        />

                        <Select value={studentForm.class_name}
                          onValueChange={(v) =>
                            setStudentForm({ ...studentForm, class_name: v })
                          }>
                          <SelectTrigger>
                            <SelectValue placeholder="Class" />
                          </SelectTrigger>
                          <SelectContent>
                            {kenyaClasses.map(c => (
                              <SelectItem key={c} value={c}>{c}</SelectItem>
                            ))}
                          </SelectContent>
                        </Select>

                        <Button className="w-full bg-amber-600 hover:bg-amber-700">
                          Submit for Approval
                        </Button>
                      </form>
                    </DialogContent>
                  </Dialog>
                </div>
              </div>
            </CardHeader>

            <CardContent>
              {filteredStudents.length === 0 ? (
                <div className="text-center py-12 text-slate-500">
                  No students found
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow className="border-[#1E293B]">
                      <TableHead>Name</TableHead>
                      <TableHead>Adm No</TableHead>
                      <TableHead>Class</TableHead>
                      <TableHead>Status</TableHead>
                    </TableRow>
                  </TableHeader>

                  <TableBody>
                    {filteredStudents.map((s) => (
                      <TableRow key={s.id}>
                        <TableCell className="text-white">{s.full_name}</TableCell>
                        <TableCell>{s.admission_number}</TableCell>
                        <TableCell>{s.class_name}</TableCell>
                        <TableCell>
                          <Badge className={approvalColor(s.approval_status)}>
                            {s.approval_status}
                          </Badge>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>

                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* ANNOUNCEMENTS */}
        <TabsContent value="announcements">
          <Card className="bg-[#1A2332] border-[#1E293B]">
            <CardHeader className="flex justify-between">
              <CardTitle className="text-white">Announcements</CardTitle>

              <Dialog open={announcementDialogOpen} onOpenChange={setAnnouncementDialogOpen}>
                <DialogTrigger asChild>
                  <Button className="bg-blue-600 hover:bg-blue-700">
                    <Plus className="w-4 h-4 mr-2" /> New
                  </Button>
                </DialogTrigger>

                <DialogContent>
                  <DialogHeader>
                    <DialogTitle>Create Announcement</DialogTitle>
                  </DialogHeader>

                  <form onSubmit={handleSubmitAnnouncement} className="space-y-4">

                    <Input
                      placeholder="Title"
                      value={announcementForm.title}
                      onChange={(e) =>
                        setAnnouncementForm({ ...announcementForm, title: e.target.value })
                      }
                    />

                    <Textarea
                      placeholder="Content"
                      value={announcementForm.content}
                      onChange={(e) =>
                        setAnnouncementForm({ ...announcementForm, content: e.target.value })
                      }
                    />

                    <Button className="w-full bg-blue-600 hover:bg-blue-700">
                      Submit
                    </Button>

                  </form>
                </DialogContent>
              </Dialog>
            </CardHeader>

            <CardContent className="space-y-3">
              {announcements.map((a) => (
                <div key={a.id} className="p-4 border border-[#1E293B] rounded-lg">
                  <div className="flex justify-between">
                    <h3 className="text-white font-semibold">{a.title}</h3>
                    <Badge className={approvalColor(a.approval_status)}>
                      {a.approval_status}
                    </Badge>
                  </div>
                  <p className="text-slate-400 text-sm">{a.content}</p>
                </div>
              ))}
            </CardContent>

          </Card>
        </TabsContent>

      </Tabs>
    </div>
  );
};

export default SecretaryPortal;
